+  // Check for istanbul/c8 coverage-summary.json
+  const summaryPaths = [
+    join(coverageDir, 'coverage-summary.json'),
+    join(coverageDir, 'coverage-final.json'),
+    join(projectRoot, '.nyc_output', 'coverage-summary.json'),
+  ];
