+    let linesFound = 0;
+    let linesHit = 0;
+    let branchesFound = 0;
+    let branchesHit = 0;
+    let functionsFound = 0;
+    let functionsHit = 0;
+
+    for (const line of lines) {
+      // Line coverage: DA:line_number,hit_count
+      if (line.startsWith('DA:')) {
+        const [lineNum, hitCount] = line.substring(3).split(',').map(Number);
+        linesFound++;
+        if (hitCount > 0) {
+          linesHit++;
