+      if (line.startsWith('FNDA:')) {
+        const [hitCount, funcName] = line.substring(5).split(',');
+        functionsFound++;
+        if (parseInt(hitCount, 10) > 0) {
+          functionsHit++;
+        } else {
+          data.uncoveredFunctions.push(funcName);
+        }
+      }
+
+      // Summary lines
+      if (line.startsWith('LF:')) {
+        data.totalLines = parseInt(line.substring(3), 10);
