+export function getFileContributors(filePath: string, cwd?: string): string[] {
+  try {
+    const result = execSync(
+      `git log --format='%an' --follow -- "${filePath}" | sort | uniq -c | sort -rn | head -5`,
+      {
+        cwd: cwd || process.cwd(),
+        encoding: 'utf-8',
+        shell: '/bin/bash',
+      }
+    );
+
+    return result
+      .trim()
+      .split('\n')
+      .filter(Boolean)
+      .map(line => line.trim().replace(/^\d+\s+/, ''))
+      .filter(Boolean);
+  } catch {
+    return [];
+  }
